declare function getWithdrawalQuote<TFromAdapterCapabilities extends AdapterCapabilities = AdapterCapabilities>(context: EarnKitContext, params: GetWithdrawalQuoteParams<TFromAdapterCapabilities>): Promise<EarnWithdrawalQuoteInfo>;

